changeSet.sql:
CREATE OR REPLACE PACKAGE NOTARIST.SET_NOTARIST_CTX AS
    -- Sets the per-session identity read by VPD policy functions via
    -- SYS_CONTEXT('NOTARIST_CTX', 'USER_ID'|'TENANT_ID'|'USER_ROLE').
    PROCEDURE set_identity(p_user_id  IN VARCHAR2,
                           p_tenant_id IN VARCHAR2,
                           p_role      IN VARCHAR2);

    -- Clears the identity so it never leaks into the next borrower of a pooled connection.
    PROCEDURE clear_identity;
END SET_NOTARIST_CTX;

CREATE OR REPLACE PACKAGE BODY NOTARIST.SET_NOTARIST_CTX AS
    PROCEDURE set_identity(p_user_id  IN VARCHAR2,
                           p_tenant_id IN VARCHAR2,
                           p_role      IN VARCHAR2) IS
    BEGIN
        DBMS_SESSION.SET_CONTEXT('NOTARIST_CTX', 'USER_ID',   p_user_id);
        DBMS_SESSION.SET_CONTEXT('NOTARIST_CTX', 'TENANT_ID', p_tenant_id);
        DBMS_SESSION.SET_CONTEXT('NOTARIST_CTX', 'USER_ROLE', p_role);
    END set_identity;

    PROCEDURE clear_identity IS
    BEGIN
        DBMS_SESSION.CLEAR_CONTEXT('NOTARIST_CTX');
    END clear_identity;
END SET_NOTARIST_CTX;

BEGIN
    EXECUTE IMMEDIATE 'GRANT EXECUTE ON NOTARIST.SET_NOTARIST_CTX TO NOTARIST_APP';
EXCEPTION
    WHEN OTHERS THEN NULL; -- app user may equal schema owner, or be provisioned separately
END;
